{
    "level": "B2–C1",
    "intro": "In this topic, you will learn <strong>impersonal passive</strong>, a construction for conveying information when the source is <strong>unknown</strong>, <strong>unimportant</strong> or when you want to make the text <strong>more formal</strong>.",
    "rules": [
        {
            "label": "Construction 1",
            "color": "emerald",
            "text": "<strong>It + is/was + V3 + that + clause</strong>:",
            "example": "It is said that he is very rich."
        },
        {
            "label": "Construction 2",
            "color": "blue",
            "text": "<strong>Subject + is/was + V3 + to + infinitive</strong>:",
            "example": "He is said to be very rich."
        },
        {
            "label": "Verbs",
            "color": "rose",
            "text": "Reporting verbs: <strong>say, believe, think, know, report, expect, consider</strong>",
            "example": "She is believed to be the best candidate."
        }
    ]
}

{
    "title": "1. Reporting verbs in the impersonal passive",
    "intro": "Verbs used in the impersonal passive:",
    "items": [
        {
            "label": "say",
            "title": "It is said that... / Subject is said to...",
            "subtitle": "They say that..."
        },
        {
            "label": "believe",
            "title": "It is believed that... / Subject is believed to...",
            "subtitle": "It is believed that..."
        },
        {
            "label": "think",
            "title": "It is thought that... / Subject is thought to...",
            "subtitle": "They believe that..."
        },
        {
            "label": "know",
            "title": "It is known that... / Subject is known to...",
            "subtitle": "It is known that..."
        },
        {
            "label": "report",
            "title": "It is reported that... / Subject is reported to...",
            "subtitle": "It is reported that..."
        },
        {
            "label": "expect",
            "title": "It is expected that... / Subject is expected to...",
            "subtitle": "It is expected that..."
        },
        {
            "label": "consider",
            "title": "It is considered that... / Subject is considered to...",
            "subtitle": "It is believed that..."
        },
        {
            "label": "suppose",
            "title": "It is supposed that... / Subject is supposed to...",
            "subtitle": "It is assumed that..."
        }
    ]
}

{
    "title": "2. Construction: It + is/was + V3 + that...",
    "sections": [
        {
            "label": "Present",
            "color": "emerald",
            "description": "<strong>It is + V3 + that...</strong> — about the present:",
            "examples": [
                {
                    "en": "It is said that he works very hard.",
                    "ua": "It is said that he works very hard."
                },
                {
                    "en": "It is believed that the company is growing.",
                    "ua": "It is believed that the company is growing."
                },
                {
                    "en": "It is reported that the situation is improving.",
                    "ua": "It is reported that the situation is improving."
                }
            ]
        },
        {
            "label": "Past",
            "color": "blue",
            "description": "<strong>It was + V3 + that...</strong> — about the past:",
            "examples": [
                {
                    "en": "It was thought that the project would fail.",
                    "ua": "It was thought that the project would fail."
                },
                {
                    "en": "It was reported that the accident happened at night.",
                    "ua": "It was reported that the accident happened at night."
                },
                {
                    "en": "It was believed that he was innocent.",
                    "ua": "It was believed that he was innocent."
                }
            ]
        },
        {
            "label": "Other tenses",
            "color": "amber",
            "description": "Other tenses: <strong>It has been said, It will be reported...</strong>:",
            "examples": [
                {
                    "en": "It has been reported that the storm is approaching.",
                    "ua": "It has been reported that the storm is approaching."
                },
                {
                    "en": "It will be announced that the winner is...",
                    "ua": "It will be announced that the winner is..."
                }
            ]
        }
    ]
}

{
    "title": "3. Construction: Subject + is/was + V3 + to + infinitive",
    "sections": [
        {
            "label": "to + Simple Infinitive",
            "color": "emerald",
            "description": "<strong>to be / to do</strong> is an action simultaneous with a reporting verb:",
            "examples": [
                {
                    "en": "He is said to be a good doctor.",
                    "ua": "He is said to be a good doctor."
                },
                {
                    "en": "She is believed to know the truth.",
                    "ua": "She is believed to know the truth."
                },
                {
                    "en": "They are reported to be in Paris.",
                    "ua": "They are reported to be in Paris."
                }
            ]
        },
        {
            "label": "to + Perfect Infinitive",
            "color": "blue",
            "description": "<strong>to have done</strong> — the action precedes the reporting verb:",
            "examples": [
                {
                    "en": "He is said to have won the lottery.",
                    "ua": "He is said to have won the lottery."
                },
                {
                    "en": "She is believed to have left the country.",
                    "ua": "She is believed to have left the country."
                },
                {
                    "en": "They are reported to have stolen millions.",
                    "ua": "They are reported to have stolen millions."
                }
            ]
        },
        {
            "label": "to + Continuous Infinitive",
            "color": "amber",
            "description": "<strong>to be doing</strong> — action in the process:",
            "examples": [
                {
                    "en": "He is said to be working on a new project.",
                    "ua": "He is said to be working on a new project."
                },
                {
                    "en": "She is believed to be living in London.",
                    "ua": "She is believed to be living in London."
                },
                {
                    "en": "They are reported to be hiding somewhere.",
                    "ua": "They are reported to be hiding somewhere."
                }
            ]
        }
    ]
}

{
    "title": "4. Transformation Active → Impersonal Passive",
    "intro": "How to turn an active sentence into an impersonal passive:",
    "rows": [
        {
            "en": "Active: People say that he is rich.",
            "ua": "Active: People say that he is rich.",
            "note": "→ It is said that he is rich. / He is said to be rich."
        },
        {
            "en": "Active: They believe that she knows the truth.",
            "ua": "Active: They believe that she knows the truth.",
            "note": "→ It is believed that... / She is believed to know..."
        },
        {
            "en": "Active: Reports say that the company is growing.",
            "ua": "Active: Reports say that the company is growing.",
            "note": "→ It is reported that... / The company is reported to be growing."
        },
        {
            "en": "Active: They thought that he had left.",
            "ua": "Active: They thought that he had left.",
            "note": "→ It was thought that... / He was thought to have left."
        }
    ],
    "warning": "📌 Use the Perfect Infinitive (to have done) if the action happened earlier!"
}

{
    "title": "5. When to use the impersonal passive?",
    "sections": [
        {
            "label": "Unknown source",
            "color": "emerald",
            "description": "When <strong>source of information is unknown</strong> or imprecise:",
            "examples": [
                {
                    "en": "It is said that the castle is haunted.",
                    "ua": "It is said that the castle is haunted."
                },
                {
                    "en": "It is believed that the earth is 4.5 billion years old.",
                    "ua": "It is believed that the earth is 4.5 billion years old."
                }
            ]
        },
        {
            "label": "Formal style",
            "color": "blue",
            "description": "In <strong>news, official documents, academic texts</strong>:",
            "examples": [
                {
                    "en": "The suspect is reported to have fled the country.",
                    "ua": "The suspect is reported to have fled the country."
                },
                {
                    "en": "The economy is expected to grow by 3%.",
                    "ua": "The economy is expected to grow by 3%."
                }
            ]
        },
        {
            "label": "Objectivity",
            "color": "amber",
            "description": "For <strong>objective presentation</strong> without personal opinion:",
            "examples": [
                {
                    "en": "It is thought that the painting is a forgery.",
                    "ua": "It is thought that the painting is a forgery."
                },
                {
                    "en": "He is considered to be an expert in the field.",
                    "ua": "He is considered to be an expert in the field."
                }
            ]
        },
        {
            "label": "Rumors, assumptions",
            "color": "rose",
            "description": "For <strong>rumors, unconfirmed data</strong>:",
            "examples": [
                {
                    "en": "The celebrity is rumored to be dating a famous actor.",
                    "ua": "The celebrity is rumored to be dating a famous actor."
                },
                {
                    "en": "It is alleged that the politician took bribes.",
                    "ua": "It is alleged that the politician took bribes."
                }
            ]
        }
    ]
}

{
    "title": "6. Other verbs in the impersonal passive",
    "intro": "Extended list of verbs:",
    "items": [
        {
            "label": "allege",
            "title": "It is alleged that...",
            "subtitle": "It is claimed (without evidence) that..."
        },
        {
            "label": "claim",
            "title": "It is claimed that...",
            "subtitle": "It is claimed that..."
        },
        {
            "label": "rumor",
            "title": "It is rumored that...",
            "subtitle": "There are rumors that..."
        },
        {
            "label": "estimate",
            "title": "It is estimated that...",
            "subtitle": "According to estimates..."
        },
        {
            "label": "assume",
            "title": "It is assumed that...",
            "subtitle": "It is assumed that..."
        },
        {
            "label": "understand",
            "title": "It is understood that...",
            "subtitle": "There is an understanding that..."
        }
    ]
}

{
    "title": "7. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Skip to before the infinitive.",
            "wrong": "He is said be rich.",
            "right": "✅ He is said to be rich."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Wrong Simple/Perfect Infinitive choice.",
            "wrong": "He is said to leave yesterday. (минула дія)",
            "right": "✅ He is said to have left yesterday."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Using that with the construction Subject + is said to...",
            "wrong": "He is said that to be rich.",
            "right": "✅ He is said to be rich."
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Incorrect reporting verb tense.",
            "wrong": "It is said that he was working there. (якщо він досі працює)",
            "right": "✅ It is said that he works there."
        }
    ]
}
